understanding_checks.code:
from typing import Protocol, runtime_checkable

@runtime_checkable
class Quacker(Protocol):
    def quack(self) -> str: ...

class Duck:
    def quack(self) -> str:
        return 'Quack'

print(isinstance(Duck(), Quacker))

from typing import Protocol

class Saver(Protocol):
    def save(self) -> None: ...

class User:
    def save(self) -> None:
        pass

def save_entity(entity: Saver) -> None:
    entity.save()

save_entity(User())

code_walkthrough.code:
from typing import Protocol

class Logger(Protocol):
    def log(self, msg: str) -> None: ...

class ConsoleLogger:
    def log(self, msg: str) -> None:
        print(f'Log: {msg}')

def process(logger: Logger) -> None:
    logger.log('Started')

process(ConsoleLogger())

