challenge.solution:
from typing import Protocol

class Notifier(Protocol):
    def notify(self, msg: str) -> None: ...

class EmailNotifier:
    def notify(self, msg: str) -> None:
        print(f'Email: {msg}')

def send_alert(notifier: Notifier) -> None:
    notifier.notify('Alert!')
